class TOTPAuthenticator:
    def __init__(self):
        self.users = {}

    def generate_secret(self, username):
        secret = pyotp.random_base32()
        self.users[username] = secret
        return secret

    def generate_qr_code(self, username, issuer_name="MyApp"):
        secret = self.users.get(username)
        if not secret:
            raise ValueError("User not found")
        totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(name=username, issuer_name=issuer_name)
        qr = qrcode.make(totp_uri)
        qr.save(f"{username}_qrcode.png")

    def validate_totp(self, username, code):
        secret = self.users.get(username)
        if not secret:
            raise ValueError("User not found")
        totp = pyotp.TOTP(secret)
        return totp.verify(code, valid_window=1)

